def sort_array(arr):
    """
    In this Kata, you have to sort an array of non-negative integers according to
    number of ones in their binary representation in ascending order.
    For similar number of ones, sort based on decimal value.
    """
    def count_ones(n):
        # For negative numbers, we need to handle them specially
        if n < 0:
            # Use two's complement representation (typically 32-bit or 64-bit)
            # Python's bin() for negative numbers shows '-0b...' so we need to count differently
            # For negative numbers in two's complement, count the 1s in the binary representation
            return bin(n).count('1')
        else:
            return bin(n).count('1')

    return sorted(arr, key=lambda x: (count_ones(x), x))
